mapper.select:
SELECT NEWS_INFO_ID
FROM NEWS_INFO
WHERE ARTICLE_LINK = #{articleLink, jdbcType=VARCHAR}

	        SELECT * FROM (
            SELECT NEWS_INFO_ID, ARTICLE_LINK, NEWS_TITLE, NEWS_DESCRIPTION, PUBLISHER, PRIMARY_LABEL, KEYWORD_KIND, PUBLISHED_AT, UPDATED_AT
            FROM NEWS_INFO
            ORDER BY PUBLISHED_AT DESC
        ) WHERE ROWNUM <= #{limit}

		    SELECT * FROM (
            SELECT ni.NEWS_INFO_ID, ni.ARTICLE_LINK, ni.NEWS_TITLE, ni.NEWS_DESCRIPTION, ni.PUBLISHER, ni.PRIMARY_LABEL, ni.KEYWORD_KIND, ni.PUBLISHED_AT, ni.UPDATED_AT
            FROM NEWS_INFO ni
            INNER JOIN NEWS_INFO_STOCK nis ON ni.NEWS_INFO_ID = nis.NEWS_INFO_ID
            WHERE nis.STOCK_CODE = #{stockCode, jdbcType=VARCHAR}
            ORDER BY ni.PUBLISHED_AT DESC
        ) WHERE ROWNUM <= #{limit}

SELECT nis.NEWS_INFO_ID, s.STOCK_CODE, s.STOCK_NAME, t.CHANGE_RATE FROM NEWS_INFO_STOCK nis JOIN STOCKS s ON s.STOCK_CODE = nis.STOCK_CODE LEFT JOIN ( SELECT STOCK_CODE, CHANGE_RATE, ROW_NUMBER() OVER ( PARTITION BY STOCK_CODE ORDER BY TRADE_TIME DESC ) rn FROM STOCK_REALTIME_TICK ) t ON t.STOCK_CODE = s.STOCK_CODE AND t.rn = 1 WHERE nis.NEWS_INFO_ID IN
#{id}
ORDER BY nis.NEWS_INFO_ID, s.STOCK_CODE
